 3→import io.jsonwebtoken.Claims;
 4→import io.jsonwebtoken.Jwts;
 5→import io.jsonwebtoken.io.Decoders;
 6→import io.jsonwebtoken.security.Keys;
 7→import org.springframework.beans.factory.annotation.Value;
 8→import org.springframework.stereotype.Component;
 9→
10→import javax.crypto.SecretKey;
11→import java.util.Date;
12→
13→/**
14→ * JWT 工具类
15→ */
16→@Component
17→public class JwtUtil {
18→
19→    private final SecretKey key;
20→    private final long expiration;
21→
22→    public JwtUtil(@Value("${jwt.secret}") String secret,
23→                   @Value("${jwt.expiration}") long expiration) {
24→        this.key = Keys.hmacShaKeyFor(Decoders.BASE64.decode(secret));
25→        this.expiration = expiration;
26→    }
27→
28→    /**
29→     * 生成 JWT token
30→     */
31→    public String generateToken(Long userId, Boolean isAdmin) {
32→        Date now = new Date();
33→        return Jwts.builder()
34→                .claim("userId", userId)
35→                .claim("isAdmin", isAdmin)
36→                .issuedAt(now)
37→                .expiration(new Date(now.getTime() + expiration))
38→                .signWith(key)
39→                .compact();
40→    }
41→
42→    /**
43→     * 解析 token，返回 Claims
44→     */
45→    public Claims parseToken(String token) {
46→        return Jwts.parser()
47→                .verifyWith(key)
48→                .build()
49→                .parseSignedClaims(token)
50→                .getPayload();
51→    }
52→
53→    /**
54→     * 从 token 中获取 userId
55→     */
56→    public Long getUserId(String token) {
57→        Claims claims = parseToken(token);
58→        return claims.get("userId", Long.class);
59→    }
60→
61→    /**
62→     * 从 token 中获取 isAdmin
63→     */
64→    public Boolean getIsAdmin(String token) {
65→        Claims claims = parseToken(token);
66→        return claims.get("isAdmin", Boolean.class);
67→    }
68→}
